const fs = require('fs');
const vocab = JSON.parse(fs.readFileSync('content/banned-vocab.json', 'utf8'));
const samples = [
  'You hear the old lock clicks open.',
  'You trade an apple for a candle.',
  'A pale bug crawls under the altar.',
  'You press your palm to the cold door.',
  'clicking beetles keep time in the wall.'
];
for (const sample of samples) {
  const hits = vocab.patterns
    .filter((entry) => new RegExp(entry.pattern, 'iu').test(sample))
    .map((entry) => entry.id);
  console.log("'`${sample} => ${hits.length ? hits.join('"', ') : 'no hits'}"'`);
}
NODE'

